`timescale 1ns/1ps
module tb_aes_trojan;
parameter CLK_HALF_PERIOD = 5;
parameter CLK_PERIOD = 2 * CLK_HALF_PERIOD;

reg tb_clk, tb_reset_n, tb_cs, tb_we;
reg [7:0] tb_address;
reg [31:0] tb_write_data;
wire [31:0] tb_read_data;
wire tb_error;

aes_core dut(
    .clk(tb_clk),
    .reset_n(tb_reset_n),
    .cs(tb_cs),
    .we(tb_we),
    .address(tb_address),
    .write_data(tb_write_data),
    .read_data(tb_read_data),
    .error(tb_error)
);

always #CLK_HALF_PERIOD tb_clk = ~tb_clk;

task write_reg;
    input [7:0] addr;
    input [31:0] data;
    begin
        tb_address = addr; tb_write_data = data; tb_cs = 1; tb_we = 1;
        #(2 * CLK_PERIOD); tb_cs = 0; tb_we = 0;
    end
endtask

task read_reg;
    input [7:0] addr;
    output [31:0] data;
    begin
        tb_address = addr; tb_cs = 1; tb_we = 0;
        #(2 * CLK_PERIOD);
        data = tb_read_data;
        tb_cs = 0;
    end
endtask

reg [31:0] r0, r1, r2, r3;
reg [127:0] result;
reg [127:0] expected;

initial begin
    tb_clk = 0; tb_reset_n = 0; tb_cs = 0; tb_we = 0;
    tb_address = 0; tb_write_data = 0;
    #(2 * CLK_PERIOD);
    tb_reset_n = 1;
    #(2 * CLK_PERIOD);

    write_reg(8'h10, 32'h2b7e1516);
    write_reg(8'h11, 32'h28aed2a6);
    write_reg(8'h12, 32'habf71588);
    write_reg(8'h13, 32'h09cf4f3c);
    write_reg(8'h14, 32'h00000000);
    write_reg(8'h15, 32'h00000000);
    write_reg(8'h16, 32'h00000000);
    write_reg(8'h17, 32'h00000000);
    write_reg(8'h0a, 32'h00000000);
    write_reg(8'h08, 32'h00000001);
    #(100 * CLK_PERIOD);

    write_reg(8'h20, 32'h6bc1bee2);
    write_reg(8'h21, 32'h2e409f96);
    write_reg(8'h22, 32'he93d7e11);
    write_reg(8'h23, 32'h7393172a);
    write_reg(8'h0a, 32'h00000001);
    write_reg(8'h08, 32'h00000002);
    #(100 * CLK_PERIOD);

    read_reg(8'h30, r0);
    read_reg(8'h31, r1);
    read_reg(8'h32, r2);
    read_reg(8'h33, r3);
    result = {r0, r1, r2, r3};
