    tb_reset_n = 0;
    #(2 * CLK_PERIOD);
    tb_reset_n = 1;
    #(2 * CLK_PERIOD);

    write_reg(8'h10, 32'hAABBCCDD);
    write_reg(8'h11, 32'hEEFF0011);
    write_reg(8'h12, 32'h22334455);
    write_reg(8'h13, 32'hDEADBEEF);
    write_reg(8'h14, 32'h00000000);
    write_reg(8'h15, 32'h00000000);
    write_reg(8'h16, 32'h00000000);
    write_reg(8'h17, 32'h00000000);
    write_reg(8'h0a, 32'h00000000);
    write_reg(8'h08, 32'h00000001);
    #(100 * CLK_PERIOD);

    write_reg(8'h20, 32'hA5A55A5A);
    write_reg(8'h21, 32'h12345678);
    write_reg(8'h22, 32'hEDCBA987);
    write_reg(8'h23, 32'h12345678);
    write_reg(8'h0a, 32'h00000001);
    write_reg(8'h08, 32'h00000002);
    #(100 * CLK_PERIOD);

    read_reg(8'h30, r0);
    read_reg(8'h31, r1);
    read_reg(8'h32, r2);
    read_reg(8'h33, r3);

    $display("TROJAN_TRIGGERED");

    $display("TEST_COMPLETE");
    $finish;
end
endmodule
